 1→import { useMemo } from 'react';
 2→import type { LoanInput, PrePayment, RateChange, LoanSummary } from '../types/loan';
 3→import { generateSummary, validateLoan } from '../utils/amortization';
 4→
 5→export function useAmortization(
 6→  loan: LoanInput | null,
 7→  prePayments: PrePayment[],
 8→  rateChanges: RateChange[] = []
 9→): { summary: LoanSummary | null; error: string | null } {
10→  return useMemo(() => {
11→    if (!loan) return { summary: null, error: null };
12→    const validationError = validateLoan(loan);
13→    if (validationError) return { summary: null, error: validationError };
14→    try {
15→      const summary = generateSummary(loan, prePayments, rateChanges);
16→      return { summary, error: null };
17→    } catch (e) {
18→      return { summary: null, error: (e as Error).message };
19→    }
20→  }, [loan, prePayments, rateChanges]);
21→}
