 22→  simulatedResult?: AmortizationResult | null,
 23→) {
 24→  const { withPrePayments, withoutPrePayments } = summary;
 25→
 26→  const maxLen = Math.max(
 27→    withPrePayments.schedule.length,
 28→    withoutPrePayments.schedule.length,
 29→    simulatedResult?.schedule.length ?? 0,
 30→  );
 31→
 32→  let cumOriginal = 0;
 33→  let cumActual = 0;
 34→  let cumSimulated = 0;
