 38→      withoutPrePayments.schedule[i]?.date ??
 39→      withPrePayments.schedule[i]?.date ??
 40→      simulatedResult?.schedule[i]?.date ??
 41→      "";
 42→
 43→    cumOriginal += withoutPrePayments.schedule[i]?.interestComponent ?? 0;
 44→    cumActual += withPrePayments.schedule[i]?.interestComponent ?? 0;
 45→    if (simulatedResult) {
 46→      cumSimulated += simulatedResult.schedule[i]?.interestComponent ?? 0;
