  1→import { useRef, useEffect } from 'react';
  2→import { format } from 'date-fns';
  3→import type { AmortizationRow } from '../types/loan';
  4→import { formatCurrency, formatDate } from '../utils/formatters';
  5→
  6→interface Props {
  7→  schedule: AmortizationRow[];
  8→  isSimulated?: boolean;
  9→  actualScheduleLength?: number;
 10→  plannedPPMonths?: Set<string>;
 11→}
 12→
 13→function getCurrentMonthKey(): string {
 14→  return format(new Date(), 'yyyy-MM');
 15→}
 16→
 17→export function AmortizationTable({
 18→  schedule,
 19→  isSimulated,
 20→  actualScheduleLength,
 21→  plannedPPMonths,
 22→}: Props) {
 23→  const currentMonthKey = getCurrentMonthKey();
 24→  const currentRowRef = useRef<HTMLTableRowElement>(null);
 25→
 26→  useEffect(() => {
 27→    if (currentRowRef.current) {
 28→      currentRowRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
 29→    }
 30→  }, [schedule]);
 31→
 32→  // Detect if rates change across the schedule
 33→  const hasRateChanges = schedule.length > 1 &&
 34→    schedule.some((row, i) => i > 0 && row.annualRate !== schedule[i - 1].annualRate);
 35→
 36→  return (
 37→    <div className="rounded-xl border border-gray-200 bg-white shadow-sm">
 38→      <div className="p-6 pb-0">
 39→        <h2 className="text-lg font-semibold text-gray-900">
 40→          Amortization Schedule
 41→          {isSimulated && (
 42→            <span className="ml-2 text-sm font-normal text-amber-600">(simulated)</span>
 43→          )}
 44→        </h2>
 45→        <p className="text-sm text-gray-500 mt-1">
 46→          {schedule.length} months
 47→          {isSimulated && actualScheduleLength && actualScheduleLength !== schedule.length && (
 48→            <span className="text-amber-600">
 49→              {' '}(was {actualScheduleLength} months)
 50→            </span>
 51→          )}
 52→        </p>
 53→      </div>
 54→      <div className="overflow-x-auto p-4">
 55→        <table className="w-full text-left text-sm">
 56→          <thead>
 57→            <tr className="border-b border-gray-200 text-gray-600">
 58→              <th className="pb-2 pr-3 font-medium">#</th>
 59→              <th className="pb-2 pr-3 font-medium">Date</th>
 60→              {hasRateChanges && (
 61→                <th className="pb-2 pr-3 font-medium text-right">Rate</th>
 62→              )}
 63→              <th className="pb-2 pr-3 font-medium text-right">Opening Bal.</th>
 64→              <th className="pb-2 pr-3 font-medium text-right">Interest</th>
 65→              <th className="pb-2 pr-3 font-medium text-right">Principal</th>
 66→              <th className="pb-2 pr-3 font-medium text-right">Pre-Payment</th>
 67→              <th className="pb-2 pr-3 font-medium text-right">Total Paid</th>
 68→              <th className="pb-2 pr-3 font-medium text-right">Total Interest Paid</th>
 69→              <th className="pb-2 pr-3 font-medium text-right">Total Principal Paid</th>
 70→              <th className="pb-2 font-medium text-right">Closing Bal.</th>
 71→            </tr>
 72→          </thead>
 73→          <tbody>
 74→            {(() => {
 75→              let cumulativeInterest = 0;
 76→              let cumulativePrincipal = 0;
 77→              return schedule.map((row) => {
 78→                cumulativeInterest += row.interestComponent;
 79→                cumulativePrincipal += row.principalComponent + row.prePayment;
 80→                const rowMonthKey = row.date.substring(0, 7); // yyyy-MM
 81→                const isCurrentMonth = rowMonthKey === currentMonthKey;
 82→                const rateChanged =
 83→                  hasRateChanges &&
 84→                  row.month > 1 &&
 85→                  row.annualRate !== schedule[row.month - 2]?.annualRate;
 86→                const isPlannedPP = plannedPPMonths?.has(rowMonthKey) && row.prePayment > 0;
 87→
 88→                let rowClass = 'border-b border-gray-100 last:border-0';
 89→                if (isCurrentMonth) {
 90→                  rowClass += ' bg-blue-100 ring-2 ring-blue-400 ring-inset';
 91→                } else if (isPlannedPP) {
 92→                  rowClass += ' bg-amber-50 border-l-4 border-l-amber-400';
 93→                } else if (row.prePayment > 0) {
 94→                  rowClass += ' bg-green-50';
 95→                } else if (rateChanged) {
 96→                  rowClass += ' bg-indigo-50';
 97→                }
 98→
 99→                return (
100→                  <tr
101→                    key={row.month}
102→                    ref={isCurrentMonth ? currentRowRef : undefined}
103→                    className={rowClass}
104→                  >
105→                    <td className="py-2 pr-3 text-gray-500">
106→                      {isCurrentMonth ? (
107→                        <span className="inline-flex items-center gap-1">
108→                          {row.month}
109→                          <span className="rounded bg-blue-600 px-1.5 py-0.5 text-[10px] font-bold text-white leading-none">
110→                            NOW
111→                          </span>
112→                        </span>
113→                      ) : isPlannedPP ? (
114→                        <span className="inline-flex items-center gap-1">
115→                          {row.month}
116→                          <span className="rounded bg-amber-500 px-1.5 py-0.5 text-[10px] font-bold text-white leading-none">
117→                            PLAN
118→                          </span>
119→                        </span>
120→                      ) : (
121→                        row.month
122→                      )}
123→                    </td>
124→                    <td className="py-2 pr-3 whitespace-nowrap">
125→                      {formatDate(row.date)}
126→                    </td>
127→                    {hasRateChanges && (
128→                      <td className={`py-2 pr-3 text-right tabular-nums ${rateChanged ? 'font-semibold text-indigo-700' : 'text-gray-500'}`}>
129→                        {row.annualRate}%
130→                      </td>
131→                    )}
132→                    <td className="py-2 pr-3 text-right tabular-nums">
133→                      {formatCurrency(row.openingBalance)}
134→                    </td>
135→                    <td className="py-2 pr-3 text-right tabular-nums text-red-600">
136→                      {formatCurrency(row.interestComponent)}
137→                    </td>
138→                    <td className="py-2 pr-3 text-right tabular-nums text-green-700">
139→                      {formatCurrency(row.principalComponent)}
140→                    </td>
141→                    <td className="py-2 pr-3 text-right tabular-nums">
142→                      {row.prePayment > 0 ? (
143→                        <span className={`font-medium ${isPlannedPP ? 'text-amber-600' : 'text-blue-600'}`}>
144→                          {formatCurrency(row.prePayment)}
145→                        </span>
146→                      ) : (
147→                        <span className="text-gray-300">-</span>
148→                      )}
149→                    </td>
150→                    <td className="py-2 pr-3 text-right tabular-nums">
151→                      {formatCurrency(row.totalPayment)}
152→                    </td>
153→                    <td className="py-2 pr-3 text-right tabular-nums text-red-600">
154→                      {formatCurrency(cumulativeInterest)}
155→                    </td>
156→                    <td className="py-2 pr-3 text-right tabular-nums text-green-700">
157→                      {formatCurrency(cumulativePrincipal)}
158→                    </td>
159→                    <td className="py-2 text-right tabular-nums font-medium">
160→                      {formatCurrency(row.closingBalance)}
161→                    </td>
162→                  </tr>
163→                );
164→              });
165→            })()}
166→          </tbody>
167→        </table>
168→      </div>
169→    </div>
170→  );
171→}
